const candidato = $('📋 AIRTABLE — Crear Registro Candidato').first().json;
const perfil    = $('🎯 AIRTABLE — Obtener Perfil Activo').first().json;
const trigger   = $('📧 TRIGGER — Gmail Detectar CV').first().json;

const fromRaw = trigger.From || '';
const nombre = fromRaw.includes('<') 
  ? fromRaw.split('<')[0].replace(/"/g,'').trim() 
  : fromRaw;
const email = fromRaw.includes('<') 
  ? fromRaw.split('<')[1].replace('>','').trim() 
  : fromRaw;

// Intentar ambas estructuras de Airtable
const pFields = perfil.fields || perfil;

return [{
  json: {
    candidato_id:       candidato.id,
    candidato_nombre:   candidato.fields?.Nombre || nombre,
    candidato_email:    candidato.fields?.Email || email,
    candidato_cv:       candidato.fields?.['Cuerpo Email'] || trigger.snippet || '',
    perfil_puesto:      pFields['Puesto'] || 'Gerente de Calidad',
    perfil_obligatorio: pFields['Requisitos Obligatorios'] || '',
    perfil_deseable:    pFields['Requisitos Deseables'] || '',
    score_minimo_hitl:  Number(pFields['Score Minimo HITL']) || 7
  }
}];

