// CHECK SEGURIDAD #2: Parsear y forzar tipos correctos
const raw = $input.first().json.output 
         || $input.first().json.salida
         || $input.first().json.text 
         || '';

const clean = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

try {
  const parsed = JSON.parse(clean);
  parsed.score            = Number(parsed.score) || 0;
  parsed.anos_experiencia = Number(parsed.anos_experiencia) || 0;
  parsed.score = Math.min(Math.max(parsed.score, 0), 10);

  // Forzar recomendacion a valores válidos
  const recRaw = parsed.recomendacion || parsed['recomendación'] || '';
  parsed.recomendacion = recRaw.toUpperCase().includes('DESCARTAR') ? 'DESCARTAR' : 'AVANZAR';

  parsed.parse_error = false;
  return [{ json: parsed }];
} catch(e) {
  return [{ json: {
    score: 0,
    fortalezas: 'Error al parsear respuesta del AI Agent',
    debilidades: 'Revisar manualmente',
    resumen_ejecutivo: 'Error de procesamiento',
    puesto_detectado: 'Desconocido',
    anos_experiencia: 0,
    recomendacion: 'DESCARTAR',
    parse_error: true,
    error_detail: e.message
  }}];
}
